import{_ as a,c as i,o as s,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Fase 1: Bootstrap - Estructuración de la Idea de Producto | Tutorial de Agent App Factory","description":"Aprende cómo la fase Bootstrap transforma ideas de producto vagas en documentos input/idea.md claros y estructurados. Este tutorial explica las responsabilidades del Bootstrap Agent, el uso de la habilidad superpowers:brainstorm, la estructura estándar de idea.md y la lista de verificación de calidad.","frontmatter":{"title":"Fase 1: Bootstrap - Estructuración de la Idea de Producto | Tutorial de Agent App Factory","sidebarTitle":"Estructuración de la Idea de Producto","subtitle":"Fase 1: Bootstrap - Estructuración de la Idea de Producto","description":"Aprende cómo la fase Bootstrap transforma ideas de producto vagas en documentos input/idea.md claros y estructurados. Este tutorial explica las responsabilidades del Bootstrap Agent, el uso de la habilidad superpowers:brainstorm, la estructura estándar de idea.md y la lista de verificación de calidad.","tags":["Pipeline","Bootstrap","Idea de Producto"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"es/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"es/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),t={name:"es/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function r(n,e,l,d,c,p){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="fase-1-bootstrap-estructuracion-de-la-idea-de-producto" tabindex="-1">Fase 1: Bootstrap - Estructuración de la Idea de Producto <a class="header-anchor" href="#fase-1-bootstrap-estructuracion-de-la-idea-de-producto" aria-label="Permalink to &quot;Fase 1: Bootstrap - Estructuración de la Idea de Producto&quot;">​</a></h1><p>Bootstrap es la primera fase del pipeline de Agent App Factory, responsable de organizar tu idea de producto vaga en un documento <code>input/idea.md</code> claro. Este es el punto de partida para todas las fases posteriores (PRD, UI, Tech, etc.), determinando la dirección y calidad de todo el proyecto.</p><h2 id="que-podras-hacer-despues-de-aprender-esto" tabindex="-1">Qué podrás hacer después de aprender esto <a class="header-anchor" href="#que-podras-hacer-despues-de-aprender-esto" aria-label="Permalink to &quot;Qué podrás hacer después de aprender esto&quot;">​</a></h2><ul><li>Organizar ideas de producto vagas en un documento <code>input/idea.md</code> que cumpla con la plantilla estándar</li><li>Comprender los límites de responsabilidad del Bootstrap Agent (solo recopila información, no crea requisitos)</li><li>Saber cómo usar la habilidad superpowers:brainstorm para profundizar en la idea del producto</li><li>Ser capaz de determinar qué información debe incluirse en la fase Bootstrap y qué no</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Puede que tengas una idea de producto, pero la describes de manera vaga:</p><ul><li>&quot;Quiero hacer una app de fitness&quot; (demasiado general)</li><li>&quot;Hacer una aplicación como Xiaohongshu&quot; (no menciona la diferenciación)</li><li>&quot;Los usuarios necesitan una mejor herramienta de gestión de tareas&quot; (no menciona el problema específico)</li></ul><p>Estas descripciones vagas harán que las fases posteriores (PRD, UI, Tech) carezcan de entradas claras, y la aplicación final generada puede desviarse completamente de tus expectativas.</p><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando estés listo para iniciar el pipeline y cumplas las siguientes condiciones:</p><ol><li><strong>Tener una idea de producto preliminar</strong> (aunque sea solo una frase)</li><li><strong>Aún no has comenzado a escribir el documento de requisitos</strong> (PRD está en fases posteriores)</li><li><strong>Aún no has decidido el stack tecnológico o el estilo de UI</strong> (estos están en fases posteriores)</li><li><strong>Deseas controlar el alcance del producto y evitar el sobre-diseño</strong> (la fase Bootstrap definirá explícitamente los no-objetivos)</li></ol><h2 id="🎒-preparacion-antes-de-comenzar" tabindex="-1">🎒 Preparación antes de comenzar <a class="header-anchor" href="#🎒-preparacion-antes-de-comenzar" aria-label="Permalink to &quot;🎒 Preparación antes de comenzar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerrequisitos</p><p>Antes de comenzar la fase Bootstrap, asegúrate de:</p><ul><li>✅ Haber completado la <a href="./../../start/init-project/">Inicialización del Proyecto</a></li><li>✅ Haber comprendido la <a href="./../../start/pipeline-overview/">Visión General del Pipeline de 7 Fases</a></li><li>✅ Tener instalado y configurado el asistente de IA (se recomienda Claude Code)</li><li>✅ Haber preparado tu idea de producto (aunque sea vaga)</li></ul></div><h2 id="conceptos-fundamentales" tabindex="-1">Conceptos fundamentales <a class="header-anchor" href="#conceptos-fundamentales" aria-label="Permalink to &quot;Conceptos fundamentales&quot;">​</a></h2><h3 id="¿que-es-la-fase-bootstrap" tabindex="-1">¿Qué es la fase Bootstrap? <a class="header-anchor" href="#¿que-es-la-fase-bootstrap" aria-label="Permalink to &quot;¿Qué es la fase Bootstrap?&quot;">​</a></h3><p><strong>Bootstrap</strong> es el punto de partida de todo el pipeline, y su única responsabilidad es <strong>organizar las ideas de producto fragmentadas en un documento estructurado</strong>.</p><div class="info custom-block"><p class="custom-block-title">No es un Product Manager</p><p>El Bootstrap Agent no es un Product Manager, no creará requisitos ni diseñará funciones por ti. Su tarea es:</p><ul><li>Recopilar la información que ya has proporcionado</li><li>Organizar y estructurar esta información</li><li>Presentarla según la plantilla estándar</li></ul><p>No decidirá &quot;qué funciones debería tener&quot;, solo te ayudará a expresar claramente &quot;qué es lo que quieres&quot;.</p></div><h3 id="¿por-que-estructurar" tabindex="-1">¿Por qué estructurar? <a class="header-anchor" href="#¿por-que-estructurar" aria-label="Permalink to &quot;¿Por qué estructurar?&quot;">​</a></h3><p>Imagina que le dices a un chef: &quot;Quiero comer algo rico&quot;</p><ul><li>❌ Descripción vaga: el chef solo puede adivinar, y podría preparar algo que no quieres comer en absoluto</li><li>✅ Descripción estructurada: &quot;Quiero un plato picante de Sichuan, sin cilantro, que sea bueno para acompañar el arroz&quot;</li></ul><p>La fase Bootstrap transforma &quot;quiero comer algo rico&quot; en &quot;plato picante de Sichuan sin cilantro&quot;.</p><h3 id="estructura-del-documento-de-salida" tabindex="-1">Estructura del documento de salida <a class="header-anchor" href="#estructura-del-documento-de-salida" aria-label="Permalink to &quot;Estructura del documento de salida&quot;">​</a></h3><p>La fase Bootstrap generará <code>input/idea.md</code>, que contiene los siguientes capítulos:</p><table tabindex="0"><thead><tr><th>Capítulo</th><th>Contenido</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>Descripción breve</strong></td><td>Resumen del producto en 1-2 frases</td><td>&quot;Una aplicación móvil de contabilidad que ayuda a los jóvenes a registrar rápidamente sus gastos diarios&quot;</td></tr><tr><td><strong>Problema (Problem)</strong></td><td>El dolor central que experimentan los usuarios</td><td>&quot;Los jóvenes descubren al final del mes que se han excedido del presupuesto, pero no saben en qué gastaron el dinero&quot;</td></tr><tr><td><strong>Usuario objetivo (Target User)</strong></td><td>Per demográfico específico</td><td>&quot;Jóvenes de 18-30 años recién incorporados al trabajo, con habilidades técnicas medias&quot;</td></tr><tr><td><strong>Valor central (Core Value)</strong></td><td>Por qué tiene valor</td><td>&quot;Contabilidad en 3 segundos, ahorrando un 80% del tiempo en comparación con la consulta manual&quot;</td></tr><tr><td><strong>Hipótesis (Assumptions)</strong></td><td>2-4 hipótesis verificables</td><td>&quot;Los usuarios están dispuestos a dedicar 2 minutos a aprender la aplicación, si pueden controlar el presupuesto&quot;</td></tr><tr><td><strong>No-objetivos (Non‑Goals)</strong></td><td>Qué no se hará explícitamente</td><td>&quot;No se hará planificación de presupuesto ni asesoramiento financiero&quot;</td></tr></tbody></table><h2 id="sigueme-paso-a-paso" tabindex="-1">Sígueme paso a paso <a class="header-anchor" href="#sigueme-paso-a-paso" aria-label="Permalink to &quot;Sígueme paso a paso&quot;">​</a></h2><h3 id="paso-1-prepara-tu-idea-de-producto" tabindex="-1">Paso 1: Prepara tu idea de producto <a class="header-anchor" href="#paso-1-prepara-tu-idea-de-producto" aria-label="Permalink to &quot;Paso 1: Prepara tu idea de producto&quot;">​</a></h3><p>Antes de iniciar el pipeline, piensa bien en tu idea de producto. Puede ser una descripción completa o simplemente una idea básica.</p><p><strong>Ejemplo</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quiero hacer una aplicación de fitness que ayude a los principiantes a registrar sus entrenamientos, incluyendo tipo de ejercicio, duración, calorías, y también poder ver las estadísticas de la semana.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">La idea puede ser muy básica</p><p>Incluso si es solo una frase, no importa. El Bootstrap Agent utilizará la habilidad superpowers:brainstorm para ayudarte a completar la información.</p></div><h3 id="paso-2-inicia-el-pipeline-en-la-fase-bootstrap" tabindex="-1">Paso 2: Inicia el pipeline en la fase Bootstrap <a class="header-anchor" href="#paso-2-inicia-el-pipeline-en-la-fase-bootstrap" aria-label="Permalink to &quot;Paso 2: Inicia el pipeline en la fase Bootstrap&quot;">​</a></h3><p>Ejecuta en el directorio del proyecto Factory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Iniciar el pipeline (si aún no está iniciado)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># O especificar directamente que comience desde bootstrap</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>La CLI mostrará el estado actual y las fases disponibles.</p><h3 id="paso-3-el-asistente-de-ia-lee-la-definicion-del-bootstrap-agent" tabindex="-1">Paso 3: El asistente de IA lee la definición del Bootstrap Agent <a class="header-anchor" href="#paso-3-el-asistente-de-ia-lee-la-definicion-del-bootstrap-agent" aria-label="Permalink to &quot;Paso 3: El asistente de IA lee la definición del Bootstrap Agent&quot;">​</a></h3><p>El asistente de IA (como Claude Code) leerá automáticamente <code>agents/bootstrap.agent.md</code> para comprender sus responsabilidades y restricciones.</p><div class="info custom-block"><p class="custom-block-title">Responsabilidades del Agent</p><p>El Bootstrap Agent solo puede:</p><ul><li>Leer la idea de producto proporcionada por el usuario en la conversación</li><li>Escribir en <code>input/idea.md</code></li></ul><p>No puede:</p><ul><li>Leer otros archivos</li><li>Escribir en otros directorios</li><li>Crear nuevos requisitos</li></ul></div><h3 id="paso-4-uso-obligatorio-de-la-habilidad-superpowers-brainstorm" tabindex="-1">Paso 4: Uso obligatorio de la habilidad superpowers:brainstorm <a class="header-anchor" href="#paso-4-uso-obligatorio-de-la-habilidad-superpowers-brainstorm" aria-label="Permalink to &quot;Paso 4: Uso obligatorio de la habilidad superpowers:brainstorm&quot;">​</a></h3><p>Este es el paso clave de la fase Bootstrap. El asistente de IA <strong>debe</strong> llamar primero a la habilidad <code>superpowers:brainstorm</code>, incluso si crees que la información ya está completa.</p><p><strong>Función de la habilidad brainstorm</strong>:</p><ol><li><strong>Profundizar en la esencia del problema</strong>: descubrir los puntos ciegos en tu descripción mediante preguntas estructuradas</li><li><strong>Clarificar el perfil del usuario objetivo</strong>: ayudarte a pensar &quot;a quién se lo vendes exactamente&quot;</li><li><strong>Validar el valor central</strong>: encontrar la diferenciación mediante la comparación con productos competidores</li><li><strong>Identificar hipótesis implícitas</strong>: enumerar esas hipótesis que das por sentadas pero no has verificado</li><li><strong>Controlar el alcance del producto</strong>: definir límites mediante los no-objetivos</li></ol><p><strong>Qué hará el asistente de IA</strong>:</p><ul><li>Llamar a la habilidad <code>superpowers:brainstorm</code></li><li>Proporcionar tu idea original</li><li>Hacerte preguntas generadas por la habilidad</li><li>Recopilar tus respuestas y perfeccionar la idea</li></ul><div class="danger custom-block"><p class="custom-block-title">Se rechazará si omites este paso</p><p>El planificador Sisyphus verificará si se utilizó la habilidad brainstorm. Si no es así, el producto generado por el Bootstrap Agent será rechazado y deberá reejecutarse.</p></div><h3 id="paso-5-confirma-el-contenido-de-idea-md" tabindex="-1">Paso 5: Confirma el contenido de idea.md <a class="header-anchor" href="#paso-5-confirma-el-contenido-de-idea-md" aria-label="Permalink to &quot;Paso 5: Confirma el contenido de idea.md&quot;">​</a></h3><p>Una vez que el Bootstrap Agent haya terminado, generará <code>input/idea.md</code>. Debes revisarlo cuidadosamente:</p><p><strong>Puntos de verificación ✅</strong>:</p><ol><li><p>¿Está clara la <strong>descripción breve</strong>?</p><ul><li>✅ Incluye: qué se hace + para quién + qué problema se resuelve</li><li>❌ Demasiado general: &quot;una herramienta para mejorar la eficiencia&quot;</li></ul></li><li><p>¿Es específica la <strong>descripción del problema</strong>?</p><ul><li>✅ Incluye: escenario + dificultad + resultado negativo</li><li>❌ Vago: &quot;la experiencia del usuario no es buena&quot;</li></ul></li><li><p>¿Está claro el <strong>usuario objetivo</strong>?</p><ul><li>✅ Tiene un perfil específico (edad/profesión/habilidad técnica)</li><li>❌ Vago: &quot;todos&quot;</li></ul></li><li><p>¿Es cuantificable el <strong>valor central</strong>?</p><ul><li>✅ Tiene beneficios específicos (ahorra un 80% del tiempo)</li><li>❌ Vago: &quot;mejora la eficiencia&quot;</li></ul></li><li><p>¿Son <strong>verificables las hipótesis</strong>?</p><ul><li>✅ Pueden verificarse mediante investigación de usuarios</li><li>❌ Juicio subjetivo: &quot;a los usuarios les gustará&quot;</li></ul></li><li><p>¿Son suficientes los <strong>no-objetivos</strong>?</p><ul><li>✅ Enumera al menos 3 funciones que no se harán</li><li>❌ Faltan o son muy pocos</li></ul></li></ol><h3 id="paso-6-elige-continuar-reintentar-o-pausar" tabindex="-1">Paso 6: Elige continuar, reintentar o pausar <a class="header-anchor" href="#paso-6-elige-continuar-reintentar-o-pausar" aria-label="Permalink to &quot;Paso 6: Elige continuar, reintentar o pausar&quot;">​</a></h3><p>Después de la confirmación, la CLI mostrará las opciones:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Selecciona</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> una</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> operación:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] Continuar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">entrar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> en</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PRD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] Reintentar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">regenerar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> idea.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] Pausar (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">continuar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> más</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tarde</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Se recomienda revisar primero en el editor de código</p><p>Antes de confirmar con el asistente de IA, abre primero <code>input/idea.md</code> en el editor de código y revisa palabra por palabra. Una vez que entres en la fase PRD, el costo de modificación será mayor.</p></div><h2 id="advertencias-de-errores-comunes" tabindex="-1">Advertencias de errores comunes <a class="header-anchor" href="#advertencias-de-errores-comunes" aria-label="Permalink to &quot;Advertencias de errores comunes&quot;">​</a></h2><h3 id="error-1-descripcion-de-la-idea-demasiado-vaga" tabindex="-1">Error 1: Descripción de la idea demasiado vaga <a class="header-anchor" href="#error-1-descripcion-de-la-idea-demasiado-vaga" aria-label="Permalink to &quot;Error 1: Descripción de la idea demasiado vaga&quot;">​</a></h3><p><strong>Ejemplo incorrecto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quiero hacer una aplicación de fitness</span></span></code></pre></div><p><strong>Consecuencia</strong>: El Bootstrap Agent hará muchas preguntas a través de la habilidad brainstorm para completar la información.</p><p><strong>Recomendación</strong>: Describe claramente desde el principio:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quiero hacer una aplicación móvil de fitness que ayude a los principiantes a registrar sus entrenamientos, incluyendo tipo de ejercicio, duración, calorías, y también poder ver las estadísticas de la semana.</span></span></code></pre></div><h3 id="error-2-incluir-detalles-de-implementacion-tecnica" tabindex="-1">Error 2: Incluir detalles de implementación técnica <a class="header-anchor" href="#error-2-incluir-detalles-de-implementacion-tecnica" aria-label="Permalink to &quot;Error 2: Incluir detalles de implementación técnica&quot;">​</a></h3><p><strong>Ejemplo incorrecto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Espero usar React Native para el frontend, Express para el backend, Prisma para la base de datos...</span></span></code></pre></div><p><strong>Consecuencia</strong>: El Bootstrap Agent rechazará este contenido (solo recopila ideas de producto, el stack tecnológico se decide en la fase Tech).</p><p><strong>Recomendación</strong>: Solo di &quot;qué hacer&quot;, no &quot;cómo hacerlo&quot;.</p><h3 id="error-3-descripcion-del-usuario-objetivo-demasiado-general" tabindex="-1">Error 3: Descripción del usuario objetivo demasiado general <a class="header-anchor" href="#error-3-descripcion-del-usuario-objetivo-demasiado-general" aria-label="Permalink to &quot;Error 3: Descripción del usuario objetivo demasiado general&quot;">​</a></h3><p><strong>Ejemplo incorrecto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Todas las personas que necesitan hacer ejercicio</span></span></code></pre></div><p><strong>Consecuencia</strong>: Las fases posteriores no podrán determinar una dirección de diseño clara.</p><p><strong>Recomendación</strong>: Define claramente el perfil:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Principiantes de fitness de 18-30 años, recién comenzando el entrenamiento sistemático, con habilidades técnicas medias, que desean registrar y ver estadísticas de manera sencilla.</span></span></code></pre></div><h3 id="error-4-no-objetivos-faltantes-o-insuficientes" tabindex="-1">Error 4: No-objetivos faltantes o insuficientes <a class="header-anchor" href="#error-4-no-objetivos-faltantes-o-insuficientes" aria-label="Permalink to &quot;Error 4: No-objetivos faltantes o insuficientes&quot;">​</a></h3><p><strong>Ejemplo incorrecto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No-objetivos: ninguno</span></span></code></pre></div><p><strong>Consecuencia</strong>: Las fases posteriores de PRD y Code pueden sobre-diseñar, aumentando la complejidad técnica.</p><p><strong>Recomendación</strong>: Enumera al menos 3 elementos:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No-objetivos:</span></span>
<span class="line"><span>- Funciones de colaboración en equipo y social (MVP se enfoca en el individuo)</span></span>
<span class="line"><span>- Análisis complejo de datos e informes</span></span>
<span class="line"><span>- Integración con dispositivos de fitness de terceros</span></span></code></pre></div><h3 id="error-5-hipotesis-no-verificables" tabindex="-1">Error 5: Hipótesis no verificables <a class="header-anchor" href="#error-5-hipotesis-no-verificables" aria-label="Permalink to &quot;Error 5: Hipótesis no verificables&quot;">​</a></h3><p><strong>Ejemplo incorrecto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hipótesis: a los usuarios les gustará nuestro diseño</span></span></code></pre></div><p><strong>Consecuencia</strong>: No se puede verificar mediante investigación de usuarios, el MVP puede fallar.</p><p><strong>Recomendación</strong>: Escribe hipótesis verificables:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hipótesis: los usuarios están dispuestos a dedicar 5 minutos a aprender la aplicación, si puede ayudar a registrar sistemáticamente los entrenamientos.</span></span></code></pre></div><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>El núcleo de la fase Bootstrap es la <strong>estructuración</strong>:</p><ol><li><strong>Entrada</strong>: tu idea de producto vaga</li><li><strong>Proceso</strong>: el asistente de IA profundiza mediante la habilidad superpowers:brainstorm</li><li><strong>Salida</strong>: <code>input/idea.md</code> que cumple con la plantilla estándar</li><li><strong>Verificación</strong>: verificar si la descripción es específica, el usuario está claro, el valor es cuantificable</li></ol><div class="tip custom-block"><p class="custom-block-title">Principio clave</p><ul><li>❌ Qué no hacer: no crear requisitos, no diseñar funciones, no decidir el stack tecnológico</li><li>✅ Qué sí hacer: recopilar información, organizarla, presentarla según la plantilla</li></ul></div><h2 id="avance-de-la-proxima-leccion" tabindex="-1">Avance de la próxima lección <a class="header-anchor" href="#avance-de-la-proxima-leccion" aria-label="Permalink to &quot;Avance de la próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../stage-prd/">Fase 2: PRD - Generación del Documento de Requisitos del Producto</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo transformar idea.md en un PRD de nivel MVP</li><li>Qué contiene el PRD (historias de usuario, lista de funciones, requisitos no funcionales)</li><li>Cómo definir el alcance y prioridades del MVP</li><li>Por qué el PRD no puede contener detalles técnicos</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Número de línea</th></tr></thead><tbody><tr><td>Definición del Bootstrap Agent</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>Definición del pipeline (fase Bootstrap)</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>Definición del planificador</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>Restricciones clave</strong>:</p><ul><li><strong>Uso obligatorio de la habilidad brainstorm</strong>: bootstrap.agent.md:70-71</li><li><strong>Prohibido incluir detalles técnicos</strong>: bootstrap.agent.md:47</li><li><strong>Prohibido fusionar múltiples ideas</strong>: bootstrap.agent.md:48</li><li><strong>El archivo de salida debe guardarse en input/idea.md</strong>: bootstrap.agent.md:50</li></ul><p><strong>Condiciones de salida</strong> (pipeline.yaml:15-18):</p><ul><li>idea.md existe</li><li>idea.md describe una idea de producto coherente</li><li>El Agent ha utilizado la habilidad <code>superpowers:brainstorm</code> para profundizar</li></ul><p><strong>Marco de contenido de Skill</strong>:</p><ul><li><strong>Marco de pensamiento</strong>: extracción vs creación, prioridad del problema, concreción, verificación de hipótesis</li><li><strong>Plantilla de preguntas</strong>: sobre el problema, usuario objetivo, valor central, hipótesis del MVP, no-objetivos</li><li><strong>Técnicas de extracción de información</strong>: retroceder del problema desde la función, extraer requisitos de las quejas, identificar hipótesis implícitas</li><li><strong>Lista de verificación de calidad</strong>: integridad, especificidad, consistencia, elementos prohibidos</li><li><strong>Principios de decisión</strong>: priorizar preguntas, orientación al problema, lo concreto es mejor que lo abstracto, verificabilidad, control de alcance</li><li><strong>Manejo de escenarios comunes</strong>: el usuario solo proporciona una frase, describe muchas funciones, describe productos competidores, ideas contradictorias</li><li><strong>Ejemplos comparativos</strong>: idea.md deficiente vs idea.md buena</li></ul></details>`,91)])])}const g=a(t,[["render",r]]);export{h as __pageData,g as default};
